fn main() {
    let n = 3;
    match n {
        1 => println!("one"),
        2 => println!("two"),
        3 => println!("three"),
        _ => println!("other"),
    }
}

fn grade(score: u32) -> &'static str {
    match score {
        90..=100 => "A",
        80..=89  => "B",
        70..=79  => "C",
        _        => "F",
    }
}

fn main() {
    println!("{}", grade(95));
    println!("{}", grade(82));
    println!("{}", grade(60));
}

fn main() {
    for i in 1..=10 {
        let label = match i {
            1 | 2 | 3 => "small",
            4 | 5 | 6 => "medium",
            _          => "large",
        };
        println!("{}: {}", i, label);
    }
}

fn main() {
    let point = (3, -2);
    match point {
        (0, 0) => println!("origin"),
        (x, 0) => println!("on x-axis at {}", x),
        (0, y) => println!("on y-axis at {}", y),
        (x, y) => println!("at ({}, {})", x, y),
    }
}

struct Point { x: i32, y: i32 }

fn main() {
    let p = Point { x: 0, y: 7 };
    match p {
        Point { x: 0, y } => println!("on y-axis at {}", y),
        Point { x, y: 0 } => println!("on x-axis at {}", x),
        Point { x, y }    => println!("at ({}, {})", x, y),
    }
}

fn main() {
    let n = 4;
    match n {
        x if x < 0 => println!("{} is negative", x),
        x if x % 2 == 0 => println!("{} is positive even", x),
        x => println!("{} is positive odd", x),
    }
}

fn main() {
    let n = 15;
    match n {
        x @ 1..=12 => println!("{} is a month number", x),
        x @ 13..=19 => println!("{} is a teen", x),
        x => println!("{} is something else", x),
    }
}

fn main() {
    let mut stack = vec![1, 2, 3, 4, 5];
    while let Some(top) = stack.pop() {
        print!("{} ", top);
    }
    println!();
}
